import React from "react";
import { Link } from "react-router-dom";

import'./Button.css';

const Button = props => {
    if (props.herf) {
        return(
            <a
            className={`button button--${props.size || 'default'} ${props.inverse && 'button-- inverse'} ${props.danger &&'button--danger'}`}
            href={props.herf} 
            >
                {props.children}
            </a>
        );
    }

return(
    <button
    className={`button button--${props.size || 'default'} ${props.inverse && 'button-- inverse'} $ {props.danger &&'button--danger'}`}
    type={props.type}
    onclick ={props.type}
    disabled={props.disabled}
            >
                {props.children}
            </button>
);
}
